import React, { useEffect } from 'react';
import AOS from 'aos';
import 'aos/dist/aos.css';

const Hero = () => {
  useEffect(() => {
    AOS.init({
      duration: 600, // Animation duration
      easing: 'ease-in-out',
      delay: 0
    });

    AOS.refresh(); // Refresh animations on component mount
  }, []);

  return (
    <section id="hero" className="hero section light-background index-page" data-aos="zoom-out">
      <img src={`${process.env.PUBLIC_URL}/static/media/img/5651978.png`} alt="/" />
      <div className="container aos-init aos-animate">
        <div className="row justify-content-center">
          <div className="col-lg-9">
            <h2>Brandon Johnson</h2>
            <p>I'm <span className="typed" data-typed-items="Designer, Developer, Freelancer, Photographer">Photographer</span>
              <span className="typed-cursor typed-cursor--blink" aria-hidden="true">|</span>
            </p>
            <div className="social-links">
              <a href="#"><i className="bi bi-twitter-x"></i></a>
              <a href="#"><i className="bi bi-facebook"></i></a>
              <a href="#"><i className="bi bi-instagram"></i></a>
              <a href="#"><i className="bi bi-linkedin"></i></a>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Hero;
